import os

def get_file_times(file_path):
    try:
        stat_info = os.stat(file_path)
        creation_time = stat_info.st_ctime
        modification_time = stat_info.st_mtime
        return creation_time, modification_time
    except FileNotFoundError:
        return None, None
    except Exception:
        return None, None
